param(
  [string]$Prefix,
  [string]$ArtifactUrl,
  [string]$ArtifactDir,
  [switch]$FromSource,
  [switch]$WithMoonshine,
  [switch]$NoPath,
  [switch]$DryRun,
  [switch]$Force,
  [switch]$Help
)

$ScriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$Install = Join-Path $ScriptDir "install.ps1"
$Forward = @{}

if ($PSBoundParameters.ContainsKey("Prefix")) { $Forward.Prefix = $Prefix }
if ($PSBoundParameters.ContainsKey("ArtifactUrl")) { $Forward.ArtifactUrl = $ArtifactUrl }
if ($PSBoundParameters.ContainsKey("ArtifactDir")) { $Forward.ArtifactDir = $ArtifactDir }
if ($FromSource) { $Forward.FromSource = $true }
if ($WithMoonshine) { $Forward.WithMoonshine = $true }
if ($NoPath) { $Forward.NoPath = $true }
if ($DryRun) { $Forward.DryRun = $true }
if ($Force) { $Forward.Force = $true }
if ($Help) { $Forward.Help = $true }

& $Install @Forward
exit $LASTEXITCODE
